{
  "context": {
    "version": "{{version}}",
    "action": "confirm",
    "timestamp": "{{iso_date}}",
    "message_id": "{{$guid}}",
    "transaction_id": "{{transaction_id}}",
    "bap_id": "{{bap_id}}",
    "bap_uri": "{{bap_host_root}}/bap/receiver",
    "bpp_id": "{{bpp_id}}",
    "bpp_uri": "{{bpp_host_root}}/bpp/receiver",
    "ttl": "PT30S",
    "domain": "{{domain}}"
  },
  "message": {
    "order": {
      "@context": "https://raw.githubusercontent.com/beckn/protocol-specifications-v2/tags/core-2.0.0-rc-eos-release/schema/core/v2/context.jsonld",
      "@type": "beckn:Order",
      "beckn:orderStatus": "CREATED",
      "beckn:seller": "provider-solar-farm-001",
      "beckn:buyer": {
        "@context": "https://raw.githubusercontent.com/beckn/protocol-specifications-v2/tags/core-2.0.0-rc-eos-release/schema/core/v2/context.jsonld",
        "@type": "beckn:Buyer",
        "beckn:id": "buyer-001",
        "beckn:buyerAttributes": {
          "@context": "https://raw.githubusercontent.com/beckn/DEG/tags/deg-1.0.1/specification/schema/EnergyTrade/v0.3/context.jsonld",
          "@type": "EnergyCustomer",
          "meterId": "TEST_METER_BUYER",
          "utilityCustomerId": "TEST-CUST-BUYER-001",
          "utilityId": "TEST_DISCOM_BUYER"
        }
      },
      "beckn:orderAttributes": {
        "@context": "https://raw.githubusercontent.com/beckn/DEG/tags/deg-1.0.1/specification/schema/EnergyTrade/v0.3/context.jsonld",
        "@type": "EnergyTradeOrder",
        "bap_id": "p2p-trading-sandbox1.com",
        "bpp_id": "p2p-trading-sandbox2.com",
        "total_quantity": {
          "unitQuantity": 15.0,
          "unitText": "kWh"
        }
      },
